import React from "react";
import { useParams } from "react-router-dom";
import {
  Container,
  Typography,
  Grid,
  Paper,
  Avatar,
  Divider,
  List,
  ListItem,
  ListItemText,
  Button,
  Box,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Grid as MuiGrid,  
} from "@mui/material";

import { doctors } from "../data/doctors";

const DoctorProfile = () => {
  const { doctorId } = useParams();

  const doctor = doctors.find((d) => d.id === Number(doctorId));

  const [openBooking, setOpenBooking] = React.useState(false);
  const [formData, setFormData] = React.useState({
    fullName: "",
    age: "",
    contactNumber: "",
    email: "",
    preferredTime: "",
  });
  const [errors, setErrors] = React.useState({});

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
    if (errors[name]) {
      setErrors((prev) => ({ ...prev, [name]: "" }));
    }
  };


  const handleConfirmBooking = () => {
    const newErrors = {};
    let hasError = false;

    if (!formData.fullName.trim()) {
      newErrors.fullName = "Full name is required";
      hasError = true;
    }
    if (!formData.age.trim()) {
      newErrors.age = "Age is required";
      hasError = true;
    }
    if (!formData.contactNumber.trim()) {
      newErrors.contactNumber = "Contact number is required";
      hasError = true;
    }
    if (!formData.email.trim()) {
      newErrors.email = "Email is required";
      hasError = true;
    }
    if (!formData.preferredTime) {
      newErrors.preferredTime = "Preferred time is required";
      hasError = true;
    }

    setErrors(newErrors);

    if (hasError) {
      alert("Please fill all required fields!");
      return;
    }

    // Success - show confirmation with details
    alert(
      `Booking Confirmed!\n\n` +
        `Doctor: ${doctor.name}\n` +
        `Patient: ${formData.fullName}\n` +
        `Age: ${formData.age}\n` +
        `Contact: ${formData.contactNumber}\n` +
        `Email: ${formData.email}\n` +
        `Preferred Time: ${formData.preferredTime}`,
    );

    // Close dialog and reset form
    setOpenBooking(false);
    setFormData({
      fullName: "",
      age: "",
      contactNumber: "",
      email: "",
      preferredTime: "",
    });
    setErrors({});
  };

  if (!doctor) {
    return (
      <Container sx={{ py: 12, textAlign: "center" }}>
        <Typography variant="h4" color="error" gutterBottom>
          Doctor not found
        </Typography>
        <Button
          variant="contained"
          color="primary"
          sx={{ mt: 4 }}
          onClick={() => window.history.back()}
        >
          Go Back
        </Button>
      </Container>
    );
  }

  return (
    <Container
      maxWidth="xl"
      sx={{
        py: 10,
        px: { xs: 3, md: 8 },
        minHeight: "90vh",
      }}
    >
      <Paper
        elevation={6}
        sx={{
          p: { xs: 5, md: 10 },
          borderRadius: 4,
          maxWidth: 1400,
          mx: "auto",
          backgroundColor: "#ffffff",
          boxShadow: "0 16px 60px rgba(0,0,0,0.15)",
        }}
      >
        <Grid container spacing={8}>
          {/* Photo + Name Section */}
          <Grid item xs={12} md={5}>
            <Box sx={{ textAlign: "center" }}>
              <Avatar
                src={doctor.image}
                alt={doctor.name}
                sx={{
                  width: { xs: 280, md: 420 },
                  height: { xs: 280, md: 420 },
                  mx: "auto",
                  mb: 5,
                  border: "8px solid #e3f2fd",
                  boxShadow: 8,
                }}
              />
              <Typography variant="h3" sx={{ fontWeight: "bold", mb: 1 }}>
                {doctor.name}
              </Typography>
              <Typography variant="h5" color="primary">
                {doctor.specialty}
              </Typography>
            </Box>
          </Grid>

          {/* Details Section */}
          <Grid item xs={12} md={7}>
            <Typography
              variant="h4"
              gutterBottom
              sx={{ mb: 5, fontWeight: 600, color: "#1976d2" }}
            >
              Professional Details
            </Typography>

            <Divider sx={{ mb: 5, borderColor: "#1976d2" }} />

            <List disablePadding>
              <ListItem sx={{ py: 3 }}>
                <ListItemText
                  primary={<Typography variant="h6">Experience</Typography>}
                  secondary={
                    <Typography variant="body1" sx={{ fontSize: "1.25rem" }}>
                      {doctor.experience}
                    </Typography>
                  }
                />
              </ListItem>

              <ListItem sx={{ py: 3 }}>
                <ListItemText
                  primary={<Typography variant="h6">Qualification</Typography>}
                  secondary={
                    <Typography variant="body1" sx={{ fontSize: "1.25rem" }}>
                      {doctor.qualification}
                    </Typography>
                  }
                />
              </ListItem>

              <ListItem sx={{ py: 3 }}>
                <ListItemText
                  primary={<Typography variant="h6">Availability</Typography>}
                  secondary={
                    <Typography variant="body1" sx={{ fontSize: "1.25rem" }}>
                      {doctor.availability}
                    </Typography>
                  }
                />
              </ListItem>

              <ListItem sx={{ py: 3, alignItems: "flex-start" }}>
                <ListItemText
                  primary={<Typography variant="h6">About</Typography>}
                  secondary={
                    <Typography
                      variant="body1"
                      sx={{ fontSize: "1.25rem", lineHeight: 1.8 }}
                    >
                      {doctor.bio}
                    </Typography>
                  }
                />
              </ListItem>
            </List>

            {/* Book Appointment Button */}
            <Box sx={{ mt: 10, textAlign: "center" }}>
              <Button
                variant="contained"
                color="primary"
                size="large"
                sx={{
                  py: 3,
                  px: 10,
                  fontSize: "1.4rem",
                  borderRadius: 3,
                }}
                onClick={() => setOpenBooking(true)}
              >
                Book Appointment
              </Button>
            </Box>
          </Grid>
        </Grid>
      </Paper>

      {/* Booking Dialog */}
      <Dialog
        open={openBooking}
        onClose={() => setOpenBooking(false)}
        maxWidth="sm"
        fullWidth
      >
        <DialogTitle sx={{ fontWeight: "bold", color: "#1976d2" }}>
          Book Appointment with {doctor.name}
        </DialogTitle>

        <DialogContent dividers>
          <MuiGrid container spacing={3}>
            <MuiGrid item xs={12}>
              <TextField
                fullWidth
                required
                label="Full Name"
                name="fullName"
                value={formData.fullName}
                onChange={handleInputChange}
                error={!!errors.fullName}
                helperText={errors.fullName}
              />
            </MuiGrid>

            <MuiGrid item xs={12} sm={6}>
              <TextField
                fullWidth
                required
                label="Age"
                name="age"
                type="number"
                value={formData.age}
                onChange={handleInputChange}
                error={!!errors.age}
                helperText={errors.age}
              />
            </MuiGrid>

            <MuiGrid item xs={12} sm={6}>
              <TextField
                fullWidth
                required
                label="Contact Number"
                name="contactNumber"
                value={formData.contactNumber}
                onChange={handleInputChange}
                error={!!errors.contactNumber}
                helperText={errors.contactNumber}
              />
            </MuiGrid>

            <MuiGrid item xs={12}>
              <TextField
                fullWidth
                required
                label="Email"
                name="email"
                type="email"
                value={formData.email}
                onChange={handleInputChange}
                error={!!errors.email}
                helperText={errors.email}
              />
            </MuiGrid>

            <MuiGrid item xs={12}>
              <FormControl fullWidth required error={!!errors.preferredTime}>
                <InputLabel>Preferred Time</InputLabel>
                <Select
                  name="preferredTime"
                  value={formData.preferredTime}
                  label="Preferred Time"
                  onChange={handleInputChange}
                >
                  <MenuItem value="09:00 AM">09:00 AM</MenuItem>
                  <MenuItem value="10:00 AM">10:00 AM</MenuItem>
                  <MenuItem value="11:00 AM">11:00 AM</MenuItem>
                  <MenuItem value="02:00 PM">02:00 PM</MenuItem>
                  <MenuItem value="03:00 PM">03:00 PM</MenuItem>
                  <MenuItem value="04:00 PM">04:00 PM</MenuItem>
                  <MenuItem value="05:00 PM">05:00 PM</MenuItem>
                </Select>
                {errors.preferredTime && (
                  <Typography variant="caption" color="error" sx={{ mt: 0.5 }}>
                    {errors.preferredTime}
                  </Typography>
                )}
              </FormControl>
            </MuiGrid>
          </MuiGrid>
        </DialogContent>

        <DialogActions sx={{ p: 3 }}>
          <Button onClick={() => setOpenBooking(false)} variant="outlined">
            Cancel
          </Button>
          <Button
            onClick={handleConfirmBooking}
            variant="contained"
            color="primary"
          >
            Confirm Booking
          </Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default DoctorProfile;
